202 快乐数

编写一个算法来判断一个数 n 是不是快乐数。
「快乐数」 定义为：
对于一个正整数，每一次将该数替换为它每个位置上的数字的平方和。
然后重复这个过程直到这个数变为 1，也可能是 无限循环 但始终变不到 1。
如果这个过程 结果为 1，那么这个数就是快乐数。
如果 n 是 快乐数 就返回 true ；不是，则返回 false 。



使用集合

class Solution:
    def isHappy(self, n: int) -&gt; bool:
        record = set() # 因为这题我们只是想判断是否有重复值，不需要排序，不关心出现过几次

        while n != 1:
            if n in record:
                return False

            record.add(n) # set用add

            next_num = 0
            while n &gt; 0:
                digit = n % 10 # 取小数位
                next_num += digit * digit # 这个地方要用 +=，而不是 =，这里要把 每一位的平方累加起来，而不是只保留 最后一位数字的平方
                n //= 10 # 删除小数位

            n = next_num

        return True



使用集合 (不同的 while 条件)

class Solution:
   def isHappy(self, n: int) -&gt; bool:
    record = set()

    while n not in record:
        record.add(n)

        new_sum = 0
        n_str = str(n)
        for i in range(len(n_str)):
            new_sum += int(n_str[i]) ** 2
        if new_sum == 1:
            return True
        else: n = new_sum

    return False



使用数组+精简 （#为集合+精简）

class Solution:
   def isHappy(self, n: int) -&gt; bool:
    record = []
    # record = set()

    while n != 1:
        n = sum(int(i) ** 2 for i in str(n))
        if n in record:
            return False
        record.append(n)
        # record.add(n)
    return True


class Solution:
    def get_sum(self, n):
        total = 0
        while n:
            n, r = divmod(n, 10)
            total += r * r
        return total

    def isHappy(self, n: int) -&gt; bool:
        slow = n
        fast = self.get_sum(n)

        while fast != 1 and slow != fast:
            slow = self.get_sum(n)
            fast = self.get_sum(self.get_sum(fast)) # 这里fast一次走两步，所以要写两遍self.get_sum， 只写一遍的话fast就和slow的速度一样了

        return fast == 1 # == 是bool，返回为True / False， 而不是赋值给fast等于1

1 两数之和

给定一个整数数组 nums 和一个整数目标值 target，请你在该数组中找出 和为目标值 target 的那 两个 整数，并返回它们的数组下标。
你可以假设每种输入只会对应一个答案，并且你不能使用两次相同的元素。
你可以按任意顺序返回答案。
/


暴力法

class Solution(object):
    def twoSum(self, nums, target):
        """
        :type nums: List[int]
        :type target: int
        :rtype: List[int]
        """
        for i in range(len(nums)):
            for j in range(i + 1, len(nums)):
                if nums[i] + nums[j] == target:
                    return [i, j]



使用字典，不使用enumerate

# 这个解法的思路就是用target减去已经有的值判断这个差值 record里面有没有，有的话说明找到了两数之和，没有的话就继续直到nums循环完成

class Solution:
    def twoSum(self, nums: List[int], target: int) -&gt; List[int]:
        record = {} # record是读一个i存一个数字，而不是一次性读完，所以最少要读到 i=1才能判断两数之和

        for i in range(len(nums)):
            if target - nums[i] in record:
                return [record[target - nums[i]], i]
            record[nums[i]] = i # 如果只读了 i = 0 的话现在record里面只有一个数字，没法做两数之和，所以要把读的数字存进record然后读下一个

        return []



使用字典，使用enumerate

class Solution:
    def twoSum(self, nums: List[int], target: int) -&gt; List[int]:
        record = {}

        # enumerate 等价于：
        # index = 0
        # for value in nums:
            # 使用 index 和 value
            # index += 1

        # for index, value in enumerate(nums):这一行已经自动初始化并更新了 index 和 value, 所以这里我们不需要再手动初始化index, value
        for index, value in enumerate(nums):
            if target - value in record: # 遍历当前元素，并在map中寻找是否有匹配的key
                return [record[target - value], index]
            record[value] = index

        return []

383 赎金信

给你两个字符串：ransomNote 和 magazine ，判断 ransomNote 能不能由 magazine 里面的字符构成。
如果可以，返回 true ；否则返回 false 。
magazine 中的每个字符只能在 ransomNote 中使用一次。
/


使用数组

class Solution:
    def canConstruct(self, ransomNote: str, magazine: str) -&gt; bool:
      ransom_count = [0] * 26
      magazine_count = [0] * 26
      for j in ransomNote:
        ransom_count[ord(j) - ord('a')] += 1
      for j in magazine:
        magazine_count[ord(j) - ord('a')] += 1

      return all(ransom_count[i] &lt;= magazine_count[i] for i in range(26)) # ransom里面这个字母用到的次数小于magazinez， ransomNote 才能由 magazine 里面的字符构成
      # all() 返回bool值， 只要有一个是 False → 整体 False，全部是 True → 整体 True



使用Counter

from collections import Counter

class Solution:
    def canConstruct(self, ransomNote: str, magazine: str) -&gt; bool:
      # 如果还有剩余需求：
      # not (...)
      # Counter(...) != {}
      # not Counter(...) == False

      # 如果完全抵消：
      # Counter(...) == {}
      # not Counter(...) == True
      return not Counter(ransomNote) - Counter(magazine)



使用字典

class Solution:
    def canConstruct(self, ransomNote: str, magazine: str) -&gt; bool:

      # 建立库存表
      count = {}
      # counts[c] 表示字母 c 在 magazine 里还剩多少个
      for c in magazine:
        count[c] = count.get(c, 0) + 1 # get(c, 0) 保证第一次出现不会 KeyError

      # 用 ransomNote 消耗库存
      for c in ransomNote:
        # 两种失败情况
        # c not in count：magazine 里从来没有这个字母
        # count[c] = 0： 有这个字母，但已经被用光了
        if c not in count or count[c] == 0:
          return False
        count[c] -= 1 # 消耗一个字符
      return True

Kamacode 54 替换数字

给定一个字符串 s，它包含小写字母和数字字符，请编写一个函数，将字符串中的字母字符保持不变，而将每个数字字符替换为number。 例如，对于输入字符串 “a1b2c3”，函数应该将其转换为 “anumberbnumbercnumber”。

输入描述：输入一个字符串 s,s 仅包含小写字母和数字字符。
输出描述：打印一个新的字符串，其中每个数字字符都被替换为了number
输入示例：a1b2c3
输出示例：anumberbnumbercnumber

数据范围：
1 &lt;= s.length &lt; 10000。


直接替换

class Solution:
    def replaceDigits(self, s:str) -&gt; str:
        # 在python里面 字符串不能直接修改
        # 所以我们要 新建一个容器，一边遍历原字符串，一边把结果拼进去
        result = []

        for c in s:
            if '0' &lt;= c &lt;= '9':
                result.append("number")
            else:
                result.append(c)

        return ''.join(result) # 在python里面 '' 和 ""没有区别

if __name__ == "__main__":
    s = input().strip()
    sol = Solution() # Solution 记得加 ()
    print(sol.replaceDigits(s))



双指针法

# 这个解法的思路是：先统计字符串中数字的个数，从而计算出替换后字符串的最终长度，然后一次性分配好结果数组，再使用两个指针分别从原字符串和结果数组的末尾向前移动，遇到数字就在结果数组中从后往前填入 `"number"`，遇到字母则直接复制，最终将结果数组拼接成字符串返回。
class Solution:
    def replaceDigits(self, s:str) -&gt; str:
        count = sum(1 for char in s if char.isdigit()) # 先数出来一共有多少个digit
        expand_len = len(s) + count * 5 # 每一个digit被替换成'number'的时候都会多占5个格子
        res = [''] * expand_len

        old_index = len(s) - 1
        new_index = expand_len - 1

        while old_index &gt;= 0:
            if s[old_index].isdigit():
                # Python 切片是「左闭右开」，所以右边的index要 + 1
                res[new_index -5 : new_index + 1] = "number" 
                new_index -= 6
            else:
                res[new_index] = s[old_index]
                new_index -= 1
            old_index -= 1

        return ''.join(res)

if __name__ == "__main__":
    sol = Solution()

    while True:
        try:
            s = input()
            print(sol.replaceDigits(s))
        except EOFError:
            break

