150. 逆波兰表达式求值

给你一个字符串数组 tokens ，表示一个根据 逆波兰表示法 表示的算术表达式。
请你计算该表达式。返回一个表示表达式值的整数。
注意：

有效的算符为 ‘+’、‘-’、’*’ 和 ‘/’ 。
每个操作数（运算对象）都可以是一个整数或者另一个表达式。
两个整数之间的除法总是 向零截断 。
表达式中不含除零运算。
输入是一个根据逆波兰表示法表示的算术表达式。
答案及所有中间计算结果可以用 32 位 整数表示。

{width = 50%}


from operator import add, sub, mul

# / 会产生浮点数，不适合整数除法
# // 是整数运算，但对负数是向下取整
# 所以负数除法要用 abs(x)//abs(y) 再手动加符号
def div(x, y):
    return int(x / y) if x * y &gt; 0 else -(abs(x) // abs(y))

class Solution(object):
    op_map = {'+': add, '-': sub, '*': mul, '/': div} # 这里的div就是上面我们自己定义的def div

    def evalRPN(self, tokens):
        stack = []

        for token in tokens:
            if token in self.op_map:
                op2 = stack.pop()
                op1 = stack.pop()
                stack.append(self.op_map[token](op1, op2))
            else:
                stack.append(int(token)) # 这里要写成int(token), 
        return stack.pop()

给定一个二叉搜索树, 找到该树中两个指定节点的最近公共祖先。
百度百科中最近公共祖先的定义为：“对于有根树 T 的两个结点 p、q，最近公共祖先表示为一个结点 x，满足 x 是 p、q 的祖先且 x 的深度尽可能大（一个节点也可以是它自己的祖先）。”
例如，给定如下二叉搜索树: root = [6,2,8,0,4,7,9,null,null,3,5]





# Definition for a binary tree node.
# class TreeNode:
#     def __init__(self, x):
#         self.val = x
#         self.left = None
#         self.right = None

class Solution:
    def traversal(self, cur, q, p):
        if not cur:
            return cur

        if cur.val &gt; q.val and cur.val &gt; p.val: # 一起在左边
            left = self.traversal(cur.left, p, q)
            if left is not None:
                return left

        if cur.val &lt; q.val and cur.val &lt; p.val: # 一起在右边
            right = self.traversal(cur.right, p, q)
            if right is not None:
                return right

        # 情况 1：p 在左，q 在右
        # 情况 2：q 在左，p 在右
        # 情况 3：cur 本身就是 p 或 q
        return cur

    def lowestCommonAncestor(self, root: 'TreeNode', p: 'TreeNode', q: 'TreeNode') -&gt; 'TreeNode':
        return self.traversal(root, p, q)





class Solution:
    def lowestCommonAncestor(self, root, p, q):
      if root.val &gt; q.val and root.val &gt; p.val:
        return self.lowestCommonAncestor(root.left, p, q)
      elif root.val &lt; q.val and root.val &lt; p.val:
        return self.lowestCommonAncestor(root.right, p, q)
      else:
        return root





class Solution:
    def lowestCommonAncestor(self, root, p, q):
      while root:
        if root.val &gt; p.val and root.val &gt; q.val:
          root = root.left
        elif root.val &lt; p.val and root.val &lt; q.val:
          root = root.right
        else:
          return root
      return None # 迭代版本必须写return None

